class WorkflowStage {\n  final String id;\n  final String name;\n  final String icon;\n  final int order;\n  final List<String> requiredSkills;\n  final int estimatedDuration; // in minutes\n\n  WorkflowStage({\n    required this.id,\n    required this.name,\n    required this.icon,\n    required this.order,\n    required this.requiredSkills,\n    required this.estimatedDuration,\n  });\n\n  factory WorkflowStage.fromJson(Map<String, dynamic> json) {\n    return WorkflowStage(\n      id: json['id'] ?? '',\n      name: json['name'] ?? '',\n      icon: json['icon'] ?? '',\n      order: json['order'] ?? 0,\n      requiredSkills: List<String>.from(json['requiredSkills'] ?? []),\n      estimatedDuration: json['estimatedDuration'] ?? 60,\n    );\n  }\n\n  Map<String, dynamic> toJson() {\n    return {\n      'id': id,\n      'name': name,\n      'icon': icon,\n      'order': order,\n      'requiredSkills': requiredSkills,\n      'estimatedDuration': estimatedDuration,\n    };\n  }\n}\n\nclass TaskStatus {\n  static const String pending = 'pending';\n  static const String assigned = 'assigned';\n  static const String started = 'started';\n  static const String paused = 'paused';\n  static const String resumed = 'resumed';\n  static const String completed = 'completed';\n  static const String cancelled = 'cancelled';\n}\n\nclass WorkflowTask {\n  final String id;\n  final String orderId;\n  final String stageId;\n  final String stageName;\n  final String stageIcon;\n  final String? assignedToId;\n  final String? assignedToName;\n  final String status;\n  final DateTime? startedAt;\n  final DateTime? pausedAt;\n  final DateTime? resumedAt;\n  final DateTime? completedAt;\n  final DateTime createdAt;\n  final DateTime updatedAt;\n  final Map<String, dynamic> orderDetails;\n  final String? notes;\n  final List<String> images;\n  final int priority; // 1-5, 5 being highest\n\n  WorkflowTask({\n    required this.id,\n    required this.orderId,\n    required this.stageId,\n    required this.stageName,\n    required this.stageIcon,\n    this.assignedToId,\n    this.assignedToName,\n    required this.status,\n    this.startedAt,\n    this.pausedAt,\n    this.resumedAt,\n    this.completedAt,\n    required this.createdAt,\n    required this.updatedAt,\n    required this.orderDetails,\n    this.notes,\n    required this.images,\n    this.priority = 3,\n  });\n\n  factory WorkflowTask.fromJson(Map<String, dynamic> json) {\n    return WorkflowTask(\n      id: json['id'] ?? '',\n      orderId: json['orderId'] ?? '',\n      stageId: json['stageId'] ?? '',\n      stageName: json['stageName'] ?? '',\n      stageIcon: json['stageIcon'] ?? '',\n      assignedToId: json['assignedToId'],\n      assignedToName: json['assignedToName'],\n      status: json['status'] ?? TaskStatus.pending,\n      startedAt: json['startedAt'] != null ? DateTime.parse(json['startedAt']) : null,\n      pausedAt: json['pausedAt'] != null ? DateTime.parse(json['pausedAt']) : null,\n      resumedAt: json['resumedAt'] != null ? DateTime.parse(json['resumedAt']) : null,\n      completedAt: json['completedAt'] != null ? DateTime.parse(json['completedAt']) : null,\n      createdAt: DateTime.parse(json['createdAt']),\n      updatedAt: DateTime.parse(json['updatedAt']),\n      orderDetails: Map<String, dynamic>.from(json['orderDetails'] ?? {}),\n      notes: json['notes'],\n      images: List<String>.from(json['images'] ?? []),\n      priority: json['priority'] ?? 3,\n    );\n  }\n\n  Map<String, dynamic> toJson() {\n    return {\n      'id': id,\n      'orderId': orderId,\n      'stageId': stageId,\n      'stageName': stageName,\n      'stageIcon': stageIcon,\n      'assignedToId': assignedToId,\n      'assignedToName': assignedToName,\n      'status': status,\n      'startedAt': startedAt?.toIso8601String(),\n      'pausedAt': pausedAt?.toIso8601String(),\n      'resumedAt': resumedAt?.toIso8601String(),\n      'completedAt': completedAt?.toIso8601String(),\n      'createdAt': createdAt.toIso8601String(),\n      'updatedAt': updatedAt.toIso8601String(),\n      'orderDetails': orderDetails,\n      'notes': notes,\n      'images': images,\n      'priority': priority,\n    };\n  }\n\n  WorkflowTask copyWith({\n    String? status,\n    String? assignedToId,\n    String? assignedToName,\n    DateTime? startedAt,\n    DateTime? pausedAt,\n    DateTime? resumedAt,\n    DateTime? completedAt,\n    String? notes,\n    List<String>? images,\n    int? priority,\n  }) {\n    return WorkflowTask(\n      id: id,\n      orderId: orderId,\n      stageId: stageId,\n      stageName: stageName,\n      stageIcon: stageIcon,\n      assignedToId: assignedToId ?? this.assignedToId,\n      assignedToName: assignedToName ?? this.assignedToName,\n      status: status ?? this.status,\n      startedAt: startedAt ?? this.startedAt,\n      pausedAt: pausedAt ?? this.pausedAt,\n      resumedAt: resumedAt ?? this.resumedAt,\n      completedAt: completedAt ?? this.completedAt,\n      createdAt: createdAt,\n      updatedAt: DateTime.now(),\n      orderDetails: orderDetails,\n      notes: notes ?? this.notes,\n      images: images ?? this.images,\n      priority: priority ?? this.priority,\n    );\n  }\n\n  Duration? get timeSpent {\n    if (startedAt == null) return null;\n    \n    DateTime endTime = completedAt ?? DateTime.now();\n    Duration total = endTime.difference(startedAt!);\n    \n    // Subtract paused time if any\n    if (pausedAt != null && resumedAt != null) {\n      total = total - resumedAt!.difference(pausedAt!);\n    } else if (pausedAt != null && status == TaskStatus.paused) {\n      total = total - DateTime.now().difference(pausedAt!);\n    }\n    \n    return total;\n  }\n\n  bool get canStart => status == TaskStatus.assigned || status == TaskStatus.pending;\n  bool get canPause => status == TaskStatus.started || status == TaskStatus.resumed;\n  bool get canResume => status == TaskStatus.paused;\n  bool get canComplete => status == TaskStatus.started || status == TaskStatus.resumed;\n}\n\nclass StaffMember {\n  final String id;\n  final String name;\n  final String phone;\n  final String email;\n  final String role;\n  final List<String> skills;\n  final bool isAvailable;\n  final int currentTaskCount;\n  final double rating;\n  final String? profileImage;\n  final DateTime joinedAt;\n  final String fcmToken;\n\n  StaffMember({\n    required this.id,\n    required this.name,\n    required this.phone,\n    required this.email,\n    required this.role,\n    required this.skills,\n    required this.isAvailable,\n    required this.currentTaskCount,\n    required this.rating,\n    this.profileImage,\n    required this.joinedAt,\n    required this.fcmToken,\n  });\n\n  factory StaffMember.fromJson(Map<String, dynamic> json) {\n    return StaffMember(\n      id: json['id'] ?? '',\n      name: json['name'] ?? '',\n      phone: json['phone'] ?? '',\n      email: json['email'] ?? '',\n      role: json['role'] ?? '',\n      skills: List<String>.from(json['skills'] ?? []),\n      isAvailable: json['isAvailable'] ?? true,\n      currentTaskCount: json['currentTaskCount'] ?? 0,\n      rating: (json['rating'] ?? 5.0).toDouble(),\n      profileImage: json['profileImage'],\n      joinedAt: DateTime.parse(json['joinedAt']),\n      fcmToken: json['fcmToken'] ?? '',\n    );\n  }\n\n  Map<String, dynamic> toJson() {\n    return {\n      'id': id,\n      'name': name,\n      'phone': phone,\n      'email': email,\n      'role': role,\n      'skills': skills,\n      'isAvailable': isAvailable,\n      'currentTaskCount': currentTaskCount,\n      'rating': rating,\n      'profileImage': profileImage,\n      'joinedAt': joinedAt.toIso8601String(),\n      'fcmToken': fcmToken,\n    };\n  }\n}